#include <iostream>
#include <string>

class Point {
public:
    int x, y;
    Point(int _x = 0, int _y = 0) : x(_x), y(_y) {}
};

bool operator==(const Point& p1, const Point& p2) {
    return p1.x == p2.x || p1.y == p2.y;
}

void run_test(const std::string& name, const Point& p1, const Point& p2, bool expected_result) {
    bool actual_result = (p1 == p2);
    std::cout << name << ": Point(" << p1.x << "," << p1.y << ") == Point(" << p2.x << "," << p2.y << ") -> "
              << (actual_result ? "true" : "false")
              << " (Expected: " << (expected_result ? "true" : "false") << ")" << std::endl;
}

int main() {
    Point p1(1, 2);
    Point p2(1, 2);
    Point p3(1, 4);
    Point p4(3, 2);
    Point p5(3, 4);

    run_test("Test 1", p1, p2, true);
    run_test("Test 2", p1, p3, false);
    run_test("Test 3", p1, p4, false);
    run_test("Test 4", p1, p5, false);

    return 0;
}
